#include <bits/stdc++.h>
using namespace std;
int n,m,g[102],dp[102][1024][1024];
int Count(int x){
    int sum=0;
    while(x){
        sum+=x&1;
        x>>=1;
    }
    return sum;
}
int main(){
    cin>>n>>m;
    for(int i=1;i<=n;i++){
        string s;
        cin>>s;
        s=" "+s;
        for(int j=1;j<=m;j++)
            g[i]=(g[i]<<1)+(s[j]=='H');
    }
    for(int i=1;i<=n;i++)
        for(int j=0;j<1<<m;j++){
            if(j&g[i] || (j<<1)&j || (j<<2)&j || (j>>1)&j || (j>>2)&j)
                continue;
            int sj=Count(j);
            for(int k=0;k<1<<m;k++){
            	int sk=Count(k);
                if(k&g[i-1] || (k<<1)&k || (k<<2)&k || (k>>1)&k || (k>>2)&k || k&j)
                	continue;
				else if(i==1)
                    dp[i][j][k]=sj;
                else if(i==2)
                	dp[i][j][k]=sj+sk;
                else
                	for(int l=0;l<1<<m;l++)
                		if(l&k || l&j || l&g[i-2] || (l<<1)&l || (l<<2)&l || (l>>1)&l || (l>>2)&l)
                			continue;
                		else
                			dp[i][j][k]=max(dp[i][j][k],dp[i-1][k][l]+sj);
            }
        }
    int ans=0;
    for(int i=0;i<1<<m;i++)
    	for(int j=0;j<1<<m;j++)
    		ans=max(ans,dp[n][i][j]);
    cout<<ans;
    return 0;
}
